1	package issueops
2	
3	import (
4		"context"
5		"database/sql"
6		"errors"
7		"fmt"
8		"strings"
9	
10		"github.com/steveyegge/beads/internal/types"
11	)
12	
13	// AddDependencyOpts configures AddDependencyInTx behavior.
14	// When fields are left empty, AddDependencyInTx performs wisp routing
15	// automatically via IsActiveWispInTx. Callers that have already determined
16	// routing (e.g., DoltStore with its pre-tx wisp cache) can set fields
17	// explicitly to skip the redundant DB check.
18	type AddDependencyOpts struct {
19		// SourceTable is the table to validate the source issue exists in.
20		// Auto-detected via wisp routing if empty.
21		SourceTable string
22		// TargetTable is the table to validate the target issue exists in.
23		// Auto-detected via wisp routing if empty. Ignored when target validation is skipped.
24		TargetTable string
25		// WriteTable is the dependency table to insert/update/check existing deps in.
26		// Auto-detected from source wisp routing if empty.
27		WriteTable string
28		// DepTables are the tables to scan for cycle detection. The recursive CTE
29		// UNIONs all of them. Defaults to ["dependencies", "wisp_dependencies"] if empty.
30		DepTables []string
31		// IsCrossPrefix is true when source and target have different prefixes,
32		// meaning the target lives in another rig's database.
33		IsCrossPrefix bool
34	}
35	
36	// AddDependencyInTx validates and inserts a dependency within an existing
37	// transaction. It handles:
38	//   - Wisp routing (auto-detected or caller-provided)
39	//   - Source/target existence validation
40	//   - Cross-type blocking validation (GH#1495)
41	//   - Cycle detection via recursive CTE across both dependency tables
42	//   - Idempotent same-type updates (metadata only)
43	//   - Type conflict detection
44	//
45	// The caller is responsible for transaction lifecycle, dolt commits, and
46	// any cache invalidation.
47	func AddDependencyInTx(ctx context.Context, tx *sql.Tx, dep *types.Dependency, actor string, opts AddDependencyOpts) error {
48		// Auto-detect source routing if not provided.
49		sourceTable := opts.SourceTable
50		writeTable := opts.WriteTable
51		if sourceTable == "" || writeTable == "" {
52			sourceIsWisp := IsActiveWispInTx(ctx, tx, dep.IssueID)
53			st, _, _, dt := WispTableRouting(sourceIsWisp)
54			if sourceTable == "" {
55				sourceTable = st
56			}
57			if writeTable == "" {
58				writeTable = dt
59			}
60		}
61	
62		// Auto-detect target routing if not provided (skip for external/cross-prefix).
63		targetTable := opts.TargetTable
64		if targetTable == "" && !strings.HasPrefix(dep.DependsOnID, "external:") && !opts.IsCrossPrefix {
65			targetIsWisp := IsActiveWispInTx(ctx, tx, dep.DependsOnID)
66			targetTable, _, _, _ = WispTableRouting(targetIsWisp)
67		}
68		if targetTable == "" {
69			targetTable = "issues"
70		}
71	
72		depTables := opts.DepTables
73		if len(depTables) == 0 {
74			depTables = []string{"dependencies", "wisp_dependencies"}
75		}
76	
77		metadata := dep.Metadata
78		if metadata == "" {
79			metadata = "{}"
80		}
81	
82		// Validate source issue exists and get its type.
83		var sourceType string
84		//nolint:gosec // G201: sourceTable is from WispTableRouting ("issues" or "wisps")
85		if err := tx.QueryRowContext(ctx, fmt.Sprintf(`SELECT issue_type FROM %s WHERE id = ?`, sourceTable), dep.IssueID).Scan(&sourceType); err != nil {
86			if errors.Is(err, sql.ErrNoRows) {
87				return fmt.Errorf("issue %s not found", dep.IssueID)
88			}
89			return fmt.Errorf("failed to check issue existence: %w", err)
90		}
91	
92		// Validate target issue exists (skip for external and cross-prefix refs).
93		var targetType string
94		if !strings.HasPrefix(dep.DependsOnID, "external:") && !opts.IsCrossPrefix {
95			//nolint:gosec // G201: targetTable is from WispTableRouting ("issues" or "wisps")
96			if err := tx.QueryRowContext(ctx, fmt.Sprintf(`SELECT issue_type FROM %s WHERE id = ?`, targetTable), dep.DependsOnID).Scan(&targetType); err != nil {
97				if errors.Is(err, sql.ErrNoRows) {
98					return fmt.Errorf("issue %s not found", dep.DependsOnID)
99				}
100				return fmt.Errorf("failed to check target issue existence: %w", err)
101			}
102		}
103	
104		// Cross-type blocking validation (GH#1495): tasks can only block tasks,
105		// epics can only block epics.
106		if dep.Type == types.DepBlocks && targetType != "" {
107			sourceIsEpic := sourceType == string(types.TypeEpic)
108			targetIsEpic := targetType == string(types.TypeEpic)
109			if sourceIsEpic != targetIsEpic {
110				if sourceIsEpic {
111					return fmt.Errorf("epics can only block other epics, not tasks")
112				}
113				return fmt.Errorf("tasks can only block other tasks, not epics")
114			}
115		}
116	
117		// Self-dependency check
118		if dep.IssueID == dep.DependsOnID {
119			return fmt.Errorf("cannot add self-dependency: %s cannot depend on itself", dep.IssueID)
120		}
121	
122		// Cycle detection for blocking deps via recursive CTE.
123		if dep.Type == types.DepBlocks || dep.Type == types.DepConditionalBlocks {
124			// Build UNION ALL across all dep tables for the CTE.
125			var unions []string
126			for _, t := range depTables {
127				//nolint:gosec // G201: depTables are caller-controlled constants
128				unions = append(unions, fmt.Sprintf("SELECT issue_id, depends_on_id FROM %s WHERE type IN ('blocks', 'conditional-blocks')", t))
129			}
130			unionQuery := strings.Join(unions, " UNION ALL ")
131	
132			var reachable int
133			//nolint:gosec // G201: unionQuery built from caller-controlled table names
134			if err := tx.QueryRowContext(ctx, fmt.Sprintf(`
135				WITH RECURSIVE reachable AS (
136					SELECT ? AS node, 0 AS depth
137					UNION ALL
138					SELECT d.depends_on_id, r.depth + 1
139					FROM reachable r
140					JOIN (%s) d ON d.issue_id = r.node
141					WHERE r.depth < 100
142				)
143				SELECT COUNT(*) FROM reachable WHERE node = ?
144			`, unionQuery), dep.DependsOnID, dep.IssueID).Scan(&reachable); err != nil {
145				return fmt.Errorf("failed to check for dependency cycle: %w", err)
146			}
147			if reachable > 0 {
148				return fmt.Errorf("adding dependency would create a cycle")
149			}
150		}
151	
152		// Check for existing dependency between the same pair.
153		var existingType string
154		//nolint:gosec // G201: writeTable is from WispTableRouting ("dependencies" or "wisp_dependencies")
155		err := tx.QueryRowContext(ctx, fmt.Sprintf(`SELECT type FROM %s WHERE issue_id = ? AND depends_on_id = ?`, writeTable),
156			dep.IssueID, dep.DependsOnID).Scan(&existingType)
157		if err == nil {
158			if existingType == string(dep.Type) {
159				// Same type — idempotent; update metadata.
160				//nolint:gosec // G201: writeTable is from WispTableRouting
161				if _, err := tx.ExecContext(ctx, fmt.Sprintf(`UPDATE %s SET metadata = ? WHERE issue_id = ? AND depends_on_id = ?`, writeTable),
162					metadata, dep.IssueID, dep.DependsOnID); err != nil {
163					return fmt.Errorf("failed to update dependency metadata: %w", err)
164				}
165				return nil
166			}
167			return fmt.Errorf("dependency %s -> %s already exists with type %q (requested %q); remove it first with 'bd dep remove' then re-add",
168				dep.IssueID, dep.DependsOnID, existingType, dep.Type)
169		} else if !errors.Is(err, sql.ErrNoRows) {
170			return fmt.Errorf("failed to check existing dependency: %w", err)
171		}
172	
173		//nolint:gosec // G201: writeTable is from WispTableRouting
174		if _, err := tx.ExecContext(ctx, fmt.Sprintf(`
175			INSERT INTO %s (issue_id, depends_on_id, type, created_at, created_by, metadata, thread_id)
176			VALUES (?, ?, ?, NOW(), ?, ?, ?)
177		`, writeTable), dep.IssueID, dep.DependsOnID, dep.Type, actor, metadata, dep.ThreadID); err != nil {
178			return fmt.Errorf("failed to add dependency: %w", err)
179		}
180		return nil
181	}
182	
183	// RemoveDependencyInTx removes a dependency between two issues within an
184	// existing transaction. Automatically routes to wisp_dependencies if the
185	// source issue is an active wisp.
186	//
187	//nolint:gosec // G201: table names come from WispTableRouting (hardcoded constants)
188	func RemoveDependencyInTx(ctx context.Context, tx *sql.Tx, issueID, dependsOnID string) error {
189		isWisp := IsActiveWispInTx(ctx, tx, issueID)
190		_, _, _, depTable := WispTableRouting(isWisp)
191	
192		if _, err := tx.ExecContext(ctx, fmt.Sprintf(
193			`DELETE FROM %s WHERE issue_id = ? AND depends_on_id = ?`, depTable),
194			issueID, dependsOnID); err != nil {
195			return fmt.Errorf("remove dependency: %w", err)
196		}
197		return nil
198	}
199	
200	// GetIssuesByIDsInTx retrieves multiple issues by ID within an existing
201	// transaction, including labels. Automatically routes each ID to the correct
202	// table (issues/wisps). Uses batched IN clauses.
203	//
204	//nolint:gosec // G201: table names come from WispTableRouting (hardcoded constants)
205	func GetIssuesByIDsInTx(ctx context.Context, tx *sql.Tx, ids []string) ([]*types.Issue, error) {
206		if len(ids) == 0 {
207			return nil, nil
208		}
209	
210		// Partition IDs by wisp status.
211		var wispIDs, permIDs []string
212		for _, id := range ids {
213			if IsActiveWispInTx(ctx, tx, id) {
214				wispIDs = append(wispIDs, id)
215			} else {
216				permIDs = append(permIDs, id)
217			}
218		}
219	
220		var allIssues []*types.Issue
221		for _, pair := range []struct {
222			table    string
223			labelTbl string
224			ids      []string
225		}{
226			{"issues", "labels", permIDs},
227			{"wisps", "wisp_labels", wispIDs},
228		} {
229			if len(pair.ids) == 0 {
230				continue
231			}
232			for start := 0; start < len(pair.ids); start += queryBatchSize {
233				end := start + queryBatchSize
234				if end > len(pair.ids) {
235					end = len(pair.ids)
236				}
237				batch := pair.ids[start:end]
238	
239				placeholders := make([]string, len(batch))
240				args := make([]any, len(batch))
241				for i, id := range batch {
242					placeholders[i] = "?"
243					args[i] = id
244				}
245				inClause := strings.Join(placeholders, ",")
246	
247				rows, err := tx.QueryContext(ctx, fmt.Sprintf(
248					`SELECT %s FROM %s WHERE id IN (%s)`,
249					IssueSelectColumns, pair.table, inClause), args...)
250				if err != nil {
251					return nil, fmt.Errorf("get issues by IDs from %s: %w", pair.table, err)
252				}
253				issueMap := make(map[string]*types.Issue)
254				for rows.Next() {
255					issue, scanErr := ScanIssueFrom(rows)
256					if scanErr != nil {
257						_ = rows.Close()
258						return nil, fmt.Errorf("get issues by IDs: scan: %w", scanErr)
259					}
260					allIssues = append(allIssues, issue)
261					issueMap[issue.ID] = issue
262				}
263				_ = rows.Close()
264				if err := rows.Err(); err != nil {
265					return nil, fmt.Errorf("get issues by IDs: rows: %w", err)
266				}
267	
268				// Hydrate labels.
269				if len(issueMap) > 0 {
270					labelRows, err := tx.QueryContext(ctx, fmt.Sprintf(
271						`SELECT issue_id, label FROM %s WHERE issue_id IN (%s) ORDER BY issue_id, label`,
272						pair.labelTbl, inClause), args...)
273					if err != nil {
274						return nil, fmt.Errorf("get issues by IDs: labels from %s: %w", pair.labelTbl, err)
275					}
276					for labelRows.Next() {
277						var issueID, label string
278						if scanErr := labelRows.Scan(&issueID, &label); scanErr != nil {
279							_ = labelRows.Close()
280							return nil, fmt.Errorf("get issues by IDs: scan label: %w", scanErr)
281						}
282						if issue, ok := issueMap[issueID]; ok {
283							issue.Labels = append(issue.Labels, label)
284						}
285					}
286					_ = labelRows.Close()
287					if err := labelRows.Err(); err != nil {
288						return nil, fmt.Errorf("get issues by IDs: label rows: %w", err)
289					}
290				}
291			}
292		}
293	
294		return allIssues, nil
295	}
296	
297	// GetDependenciesWithMetadataInTx returns issues that the given issueID depends on,
298	// along with the dependency type. Works within an existing transaction.
299	// Queries both dependency tables to handle cross-table dependencies.
300	//
301	//nolint:gosec // G201: table names come from hardcoded constants
302	func GetDependenciesWithMetadataInTx(ctx context.Context, tx *sql.Tx, issueID string) ([]*types.IssueWithDependencyMetadata, error) {
303		type depMeta struct {
304			depID, depType string
305		}
306	
307		// Query both dependency tables to find all dependencies.
308		var deps []depMeta
309		for _, depTable := range []string{"dependencies", "wisp_dependencies"} {
310			rows, err := tx.QueryContext(ctx, fmt.Sprintf(
311				`SELECT depends_on_id, type FROM %s WHERE issue_id = ?`, depTable), issueID)
312			if err != nil {
313				return nil, fmt.Errorf("get dependencies from %s: %w", depTable, err)
314			}
315			for rows.Next() {
316				var d depMeta
317				if scanErr := rows.Scan(&d.depID, &d.depType); scanErr != nil {
318					_ = rows.Close()
319					return nil, fmt.Errorf("get dependencies: scan: %w", scanErr)
320				}
321				deps = append(deps, d)
322			}
323			_ = rows.Close()
324			if err := rows.Err(); err != nil {
325				return nil, fmt.Errorf("get dependencies: rows from %s: %w", depTable, err)
326			}
327		}
328	
329		if len(deps) == 0 {
330			return nil, nil
331		}
332	
333		// Fetch all dependency target issues.
334		ids := make([]string, len(deps))
335		for i, d := range deps {
336			ids[i] = d.depID
337		}
338		issues, err := GetIssuesByIDsInTx(ctx, tx, ids)
339		if err != nil {
340			return nil, fmt.Errorf("get dependencies: fetch issues: %w", err)
341		}
342		issueMap := make(map[string]*types.Issue, len(issues))
343		for _, iss := range issues {
344			issueMap[iss.ID] = iss
345		}
346	
347		var results []*types.IssueWithDependencyMetadata
348		for _, d := range deps {
349			issue, ok := issueMap[d.depID]
350			if !ok {
351				continue
352			}
353			results = append(results, &types.IssueWithDependencyMetadata{
354				Issue:          *issue,
355				DependencyType: types.DependencyType(d.depType),
356			})
357		}
358		return results, nil
359	}
360	
361	// GetDependentsWithMetadataInTx returns issues that depend on the given issueID
362	// along with the dependency type. Works within an existing transaction.
363	//
364	//nolint:gosec // G201: table names come from WispTableRouting (hardcoded constants)
365	func GetDependentsWithMetadataInTx(ctx context.Context, tx *sql.Tx, issueID string) ([]*types.IssueWithDependencyMetadata, error) {
366		type depMeta struct {
367			depID, depType string
368		}
369	
370		// Query both dependency tables to find all dependents.
371		var deps []depMeta
372		for _, depTable := range []string{"dependencies", "wisp_dependencies"} {
373			rows, err := tx.QueryContext(ctx, fmt.Sprintf(
374				`SELECT issue_id, type FROM %s WHERE depends_on_id = ?`, depTable), issueID)
375			if err != nil {
376				return nil, fmt.Errorf("get dependents from %s: %w", depTable, err)
377			}
378			for rows.Next() {
379				var d depMeta
380				if scanErr := rows.Scan(&d.depID, &d.depType); scanErr != nil {
381					_ = rows.Close()
382					return nil, fmt.Errorf("get dependents: scan: %w", scanErr)
383				}
384				deps = append(deps, d)
385			}
386			_ = rows.Close()
387			if err := rows.Err(); err != nil {
388				return nil, fmt.Errorf("get dependents: rows from %s: %w", depTable, err)
389			}
390		}
391	
392		if len(deps) == 0 {
393			return nil, nil
394		}
395	
396		// Fetch all dependent issues.
397		ids := make([]string, len(deps))
398		for i, d := range deps {
399			ids[i] = d.depID
400		}
401		issues, err := GetIssuesByIDsInTx(ctx, tx, ids)
402		if err != nil {
403			return nil, fmt.Errorf("get dependents: fetch issues: %w", err)
404		}
405		issueMap := make(map[string]*types.Issue, len(issues))
406		for _, iss := range issues {
407			issueMap[iss.ID] = iss
408		}
409	
410		var results []*types.IssueWithDependencyMetadata
411		for _, d := range deps {
412			issue, ok := issueMap[d.depID]
413			if !ok {
414				continue
415			}
416			results = append(results, &types.IssueWithDependencyMetadata{
417				Issue:          *issue,
418				DependencyType: types.DependencyType(d.depType),
419			})
420		}
421		return results, nil
422	}
423	
424	// GetDependenciesInTx returns issues that the given issueID depends on.
425	// Queries both dependencies and wisp_dependencies tables.
426	//
427	//nolint:gosec // G201: table names come from hardcoded constants
428	func GetDependenciesInTx(ctx context.Context, tx *sql.Tx, issueID string) ([]*types.Issue, error) {
429		var ids []string
430		for _, depTable := range []string{"dependencies", "wisp_dependencies"} {
431			rows, err := tx.QueryContext(ctx, fmt.Sprintf(
432				`SELECT depends_on_id FROM %s WHERE issue_id = ?`, depTable), issueID)
433			if err != nil {
434				return nil, fmt.Errorf("get dependencies from %s: %w", depTable, err)
435			}
436			for rows.Next() {
437				var id string
438				if scanErr := rows.Scan(&id); scanErr != nil {
439					_ = rows.Close()
440					return nil, fmt.Errorf("get dependencies: scan: %w", scanErr)
441				}
442				ids = append(ids, id)
443			}
444			_ = rows.Close()
445			if err := rows.Err(); err != nil {
446				return nil, fmt.Errorf("get dependencies: rows from %s: %w", depTable, err)
447			}
448		}
449	
450		if len(ids) == 0 {
451			return nil, nil
452		}
453	
454		return GetIssuesByIDsInTx(ctx, tx, ids)
455	}
456	
457	// GetDependentsInTx returns issues that depend on the given issueID.
458	// Queries both dependencies and wisp_dependencies tables.
459	//
460	//nolint:gosec // G201: table names come from hardcoded constants
461	func GetDependentsInTx(ctx context.Context, tx *sql.Tx, issueID string) ([]*types.Issue, error) {
462		var ids []string
463		for _, depTable := range []string{"dependencies", "wisp_dependencies"} {
464			rows, err := tx.QueryContext(ctx, fmt.Sprintf(
465				`SELECT issue_id FROM %s WHERE depends_on_id = ?`, depTable), issueID)
466			if err != nil {
467				return nil, fmt.Errorf("get dependents from %s: %w", depTable, err)
468			}
469			for rows.Next() {
470				var id string
471				if scanErr := rows.Scan(&id); scanErr != nil {
472					_ = rows.Close()
473					return nil, fmt.Errorf("get dependents: scan: %w", scanErr)
474				}
475				ids = append(ids, id)
476			}
477			_ = rows.Close()
478			if err := rows.Err(); err != nil {
479				return nil, fmt.Errorf("get dependents: rows from %s: %w", depTable, err)
480			}
481		}
482	
483		if len(ids) == 0 {
484			return nil, nil
485		}
486	
487		return GetIssuesByIDsInTx(ctx, tx, ids)
488	}
