13	// ComputeBlockedIDsInTx returns the set of issue IDs that are blocked by active issues.
14	// This is the core computation without caching — callers manage their own cache.
15	//
16	//nolint:gosec // G201: tables are hardcoded
17	func ComputeBlockedIDsInTx(ctx context.Context, tx *sql.Tx, includeWisps bool) ([]string, map[string]bool, error) {
18		issueTables := []string{"issues"}
19		depTables := []string{"dependencies"}
20		if includeWisps {
21			issueTables = append(issueTables, "wisps")
22			depTables = append(depTables, "wisp_dependencies")
23		}
24	
25		// Step 1: Get all active issue IDs
26		activeIDs := make(map[string]bool)
27		for _, table := range issueTables {
28			activeRows, err := tx.QueryContext(ctx, fmt.Sprintf(`
29				SELECT id FROM %s
30				WHERE status NOT IN ('closed', 'pinned')
31			`, table))
32			if err != nil {
33				if isTableNotExistError(err) {
34					continue
35				}
36				return nil, nil, fmt.Errorf("compute blocked IDs: active issues from %s: %w", table, err)
37			}
38			for activeRows.Next() {
39				var id string
40				if err := activeRows.Scan(&id); err != nil {
41					_ = activeRows.Close()
42					return nil, nil, fmt.Errorf("compute blocked IDs: scan active issue: %w", err)
43				}
44				activeIDs[id] = true
45			}
46			_ = activeRows.Close()
47			if err := activeRows.Err(); err != nil {
48				return nil, nil, fmt.Errorf("compute blocked IDs: active rows from %s: %w", table, err)
49			}
50		}
51	
52		// Step 2: Get blocking deps, waits-for gates, and conditional-blocks
53		type depRecord struct {
54			issueID, dependsOnID, depType string
55			metadata                      sql.NullString
56		}
57		var allDeps []depRecord
58		for _, depTable := range depTables {
59			depRows, err := tx.QueryContext(ctx, fmt.Sprintf(`
60				SELECT issue_id, depends_on_id, type, metadata FROM %s
61				WHERE type IN ('blocks', 'waits-for', 'conditional-blocks')
62			`, depTable))
63			if err != nil {
64				if isTableNotExistError(err) {
65					continue
66				}
67				return nil, nil, fmt.Errorf("compute blocked IDs: deps from %s: %w", depTable, err)
68			}
69			for depRows.Next() {
70				var rec depRecord
71				if err := depRows.Scan(&rec.issueID, &rec.dependsOnID, &rec.depType, &rec.metadata); err != nil {
72					_ = depRows.Close()
73					return nil, nil, fmt.Errorf("compute blocked IDs: scan dep: %w", err)
74				}
75				allDeps = append(allDeps, rec)
76			}
77			_ = depRows.Close()
78			if err := depRows.Err(); err != nil {
79				return nil, nil, fmt.Errorf("compute blocked IDs: dep rows from %s: %w", depTable, err)
80			}
81		}
82	
83		// Step 3: Filter direct blockers; collect waits-for edges
84		type waitsForDep struct {
85			issueID   string
86			spawnerID string
87			gate      string
88		}
89		var waitsForDeps []waitsForDep
90		needsClosedChildren := false
91	
92		blockedSet := make(map[string]bool)
93		for _, rec := range allDeps {
94			switch rec.depType {
95			case string(types.DepBlocks), string(types.DepConditionalBlocks):
96				if activeIDs[rec.issueID] && activeIDs[rec.dependsOnID] {
97					blockedSet[rec.issueID] = true
98				}
99			case string(types.DepWaitsFor):
100				if !activeIDs[rec.issueID] {
101					continue
102				}
103				gate := types.ParseWaitsForGateMetadata(rec.metadata.String)
104				if gate == types.WaitsForAnyChildren {
105					needsClosedChildren = true
106				}
107				waitsForDeps = append(waitsForDeps, waitsForDep{
108					issueID:   rec.issueID,
109					spawnerID: rec.dependsOnID,
110					gate:      gate,
111				})
112			}
113		}
114	
115		if len(waitsForDeps) > 0 {
116			// Step 4: Load direct children for each waits-for spawner.
117			spawnerIDs := make(map[string]struct{})
118			for _, dep := range waitsForDeps {
119				spawnerIDs[dep.spawnerID] = struct{}{}
120			}
121	
122			allSpawnerIDs := make([]string, 0, len(spawnerIDs))
123			for spawnerID := range spawnerIDs {
124				allSpawnerIDs = append(allSpawnerIDs, spawnerID)
125			}
126	
127			spawnerChildren := make(map[string][]string)
128			childIDs := make(map[string]struct{})
129			for _, depTbl := range depTables {
130				for start := 0; start < len(allSpawnerIDs); start += queryBatchSize {
131					end := start + queryBatchSize
132					if end > len(allSpawnerIDs) {
133						end = len(allSpawnerIDs)
134					}
135					placeholders, args := buildSQLInClause(allSpawnerIDs[start:end])
136	
137					childRows, err := tx.QueryContext(ctx, fmt.Sprintf(`
138						SELECT issue_id, depends_on_id FROM %s
139						WHERE type = 'parent-child' AND depends_on_id IN (%s)
140					`, depTbl, placeholders), args...)
141					if err != nil {
142						if isTableNotExistError(err) {
143							continue
144						}
145						return nil, nil, fmt.Errorf("compute blocked IDs: children from %s: %w", depTbl, err)
146					}
147	
148					for childRows.Next() {
149						var childID, parentID string
150						if err := childRows.Scan(&childID, &parentID); err != nil {
151							_ = childRows.Close()
152							return nil, nil, fmt.Errorf("compute blocked IDs: scan child: %w", err)
153						}
154						spawnerChildren[parentID] = append(spawnerChildren[parentID], childID)
155						childIDs[childID] = struct{}{}
156					}
157					_ = childRows.Close()
158					if err := childRows.Err(); err != nil {
159						return nil, nil, fmt.Errorf("compute blocked IDs: child rows from %s: %w", depTbl, err)
160					}
161				}
162			}
163	
164			closedChildren := make(map[string]bool)
165			if needsClosedChildren && len(childIDs) > 0 {
166				allChildIDs := make([]string, 0, len(childIDs))
167				for childID := range childIDs {
168					allChildIDs = append(allChildIDs, childID)
169				}
170	
171				for _, issueTbl := range issueTables {
172					for start := 0; start < len(allChildIDs); start += queryBatchSize {
173						end := start + queryBatchSize
174						if end > len(allChildIDs) {
175							end = len(allChildIDs)
176						}
177						placeholders, args := buildSQLInClause(allChildIDs[start:end])
178	
179						closedRows, err := tx.QueryContext(ctx, fmt.Sprintf(`
180							SELECT id FROM %s
181							WHERE status = 'closed' AND id IN (%s)
182						`, issueTbl, placeholders), args...)
183						if err != nil {
184							if isTableNotExistError(err) {
185								continue
186							}
187							return nil, nil, fmt.Errorf("compute blocked IDs: closed children from %s: %w", issueTbl, err)
188						}
189						for closedRows.Next() {
190							var childID string
191							if err := closedRows.Scan(&childID); err != nil {
192								_ = closedRows.Close()
193								return nil, nil, fmt.Errorf("compute blocked IDs: scan closed child: %w", err)
194							}
195							closedChildren[childID] = true
196						}
197						_ = closedRows.Close()
198						if err := closedRows.Err(); err != nil {
199							return nil, nil, fmt.Errorf("compute blocked IDs: closed child rows from %s: %w", issueTbl, err)
200						}
201					}
202				}
203			}
204	
205			// Step 5: Evaluate waits-for gates against current child states.
206			for _, dep := range waitsForDeps {
207				children := spawnerChildren[dep.spawnerID]
208				switch dep.gate {
209				case types.WaitsForAnyChildren:
210					if len(children) == 0 {
211						continue
212					}
213					hasClosedChild := false
214					hasActiveChild := false
215					for _, childID := range children {
216						if closedChildren[childID] {
217							hasClosedChild = true
218							break
219						}
220						if activeIDs[childID] {
221							hasActiveChild = true
222						}
223					}
224					if !hasClosedChild && hasActiveChild {
225						blockedSet[dep.issueID] = true
226					}
227				default:
228					for _, childID := range children {
229						if activeIDs[childID] {
230							blockedSet[dep.issueID] = true
231							break
232						}
233					}
234				}
235			}
236		}
237	
238		result := make([]string, 0, len(blockedSet))
239		for id := range blockedSet {
240			result = append(result, id)
241		}
242	
243		return result, activeIDs, nil
244	}
245	
246	// GetChildrenWithParentsInTx returns a map of childID -> parentID for direct children
247	// (parent-child deps) of the given parent IDs.
248	//
249	//nolint:gosec // G201: tables are hardcoded
250	func GetChildrenWithParentsInTx(ctx context.Context, tx *sql.Tx, parentIDs []string) (map[string]string, error) {
251		if len(parentIDs) == 0 {
252			return nil, nil
253		}
254		result := make(map[string]string)
255		for _, depTable := range []string{"dependencies", "wisp_dependencies"} {
256			for start := 0; start < len(parentIDs); start += queryBatchSize {
257				end := start + queryBatchSize
258				if end > len(parentIDs) {
259					end = len(parentIDs)
260				}
261				placeholders, args := buildSQLInClause(parentIDs[start:end])
262	
263				query := fmt.Sprintf(`
264					SELECT issue_id, depends_on_id FROM %s
265					WHERE type = 'parent-child' AND depends_on_id IN (%s)
266				`, depTable, placeholders)
267				rows, err := tx.QueryContext(ctx, query, args...)
268				if err != nil {
269					if isTableNotExistError(err) {
270						break
271					}
272					return nil, fmt.Errorf("get children with parents from %s: %w", depTable, err)
273				}
274				for rows.Next() {
275					var childID, parentID string
276					if err := rows.Scan(&childID, &parentID); err != nil {
277						_ = rows.Close()
278						return nil, fmt.Errorf("scan children with parents: %w", err)
279					}
280					result[childID] = parentID
281				}
282				_ = rows.Close()
283				if err := rows.Err(); err != nil {
284					return nil, fmt.Errorf("children with parents rows from %s: %w", depTable, err)
285				}
286			}
