291	// GetChildrenOfIssuesInTx returns IDs of direct children (parent-child deps) of the given issue IDs.
292	//
293	//nolint:gosec // G201: tables are hardcoded
294	func GetChildrenOfIssuesInTx(ctx context.Context, tx *sql.Tx, parentIDs []string) ([]string, error) {
295		if len(parentIDs) == 0 {
296			return nil, nil
297		}
298		var children []string
299		for _, depTable := range []string{"dependencies", "wisp_dependencies"} {
300			for start := 0; start < len(parentIDs); start += queryBatchSize {
301				end := start + queryBatchSize
302				if end > len(parentIDs) {
303					end = len(parentIDs)
304				}
305				placeholders, args := buildSQLInClause(parentIDs[start:end])
306	
307				query := fmt.Sprintf(`
308					SELECT issue_id FROM %s
309					WHERE type = 'parent-child' AND depends_on_id IN (%s)
310				`, depTable, placeholders)
311				rows, err := tx.QueryContext(ctx, query, args...)
312				if err != nil {
313					if isTableNotExistError(err) {
314						break
315					}
316					return nil, fmt.Errorf("get children of issues from %s: %w", depTable, err)
317				}
318				for rows.Next() {
319					var childID string
320					if err := rows.Scan(&childID); err != nil {
321						_ = rows.Close()
322						return nil, fmt.Errorf("scan child: %w", err)
323					}
324					children = append(children, childID)
325				}
326				_ = rows.Close()
327				if err := rows.Err(); err != nil {
328					return nil, fmt.Errorf("children rows from %s: %w", depTable, err)
329				}
