335	// GetBlockedIssuesInTx returns issues that are blocked by other issues.
336	// This is the full implementation including transitive child blocking and parent filtering.
337	//
338	//nolint:gosec // G201: tables are hardcoded
339	func GetBlockedIssuesInTx(ctx context.Context, tx *sql.Tx, filter types.WorkFilter) ([]*types.BlockedIssue, error) {
340		// Step 1: Compute blocked IDs (also returns activeIDs for later use)
341		blockedIDList, activeIDs, err := ComputeBlockedIDsInTx(ctx, tx, true)
342		if err != nil {
343			return nil, fmt.Errorf("compute blocked IDs: %w", err)
344		}
345	
346		blockedSet := make(map[string]bool, len(blockedIDList))
347		for _, id := range blockedIDList {
348			blockedSet[id] = true
349		}
350	
351		// Step 2: Include children of blocked parents (GH#1495).
352		childToParent, childErr := GetChildrenWithParentsInTx(ctx, tx, blockedIDList)
353		if childErr == nil {
354			for childID := range childToParent {
355				if activeIDs[childID] && !blockedSet[childID] {
356					blockedSet[childID] = true
357					blockedIDList = append(blockedIDList, childID)
358				}
359			}
360		}
361	
362		// Step 3: Get blocking deps to build BlockedBy lists
363		blockerMap := make(map[string][]string)
364		for _, depTable := range []string{"dependencies", "wisp_dependencies"} {
365			depRows, err := tx.QueryContext(ctx, fmt.Sprintf(`
366				SELECT issue_id, depends_on_id FROM %s
367				WHERE type IN ('blocks', 'waits-for', 'conditional-blocks')
368			`, depTable))
369			if err != nil {
370				return nil, fmt.Errorf("get blocking deps from %s: %w", depTable, err)
371			}
372	
373			for depRows.Next() {
374				var issueID, blockerID string
375				if err := depRows.Scan(&issueID, &blockerID); err != nil {
376					_ = depRows.Close()
377					return nil, fmt.Errorf("scan dependency: %w", err)
378				}
379				if blockedSet[issueID] && activeIDs[blockerID] {
380					blockerMap[issueID] = append(blockerMap[issueID], blockerID)
381				}
382			}
383			_ = depRows.Close()
384			if err := depRows.Err(); err != nil {
385				return nil, fmt.Errorf("dependency rows from %s: %w", depTable, err)
386			}
387		}
388	
389		// Step 3b: Add transitively blocked children to blockerMap (GH#1495).
390		if childErr == nil {
391			for childID, parentID := range childToParent {
392				if activeIDs[childID] && blockedSet[childID] {
393					if _, hasDirectBlocker := blockerMap[childID]; !hasDirectBlocker {
394						blockerMap[childID] = []string{parentID}
395					}
396				}
397			}
398		}
399	
400		// Step 4: Batch-fetch all blocked issues
401		blockedIDs := make([]string, 0, len(blockerMap))
402		for id := range blockerMap {
403			blockedIDs = append(blockedIDs, id)
404		}
405		issues, err := GetIssuesByIDsInTx(ctx, tx, blockedIDs)
406		if err != nil {
407			return nil, fmt.Errorf("batch-fetch blocked issues: %w", err)
408		}
409		issueMap := make(map[string]*types.Issue, len(issues))
410		for _, issue := range issues {
411			issueMap[issue.ID] = issue
412		}
413	
414		// Parent filtering: restrict to children of specified parent (GH#2009)
415		var parentChildSet map[string]bool
416		if filter.ParentID != nil {
417			parentChildSet = make(map[string]bool)
418			parentID := *filter.ParentID
419			children, childErr := GetChildrenOfIssuesInTx(ctx, tx, []string{parentID})
420			if childErr == nil {
421				for _, childID := range children {
422					parentChildSet[childID] = true
423				}
424			}
425			// Also include dotted-ID children (e.g., "parent.1.2")
426			for id := range blockerMap {
427				if strings.HasPrefix(id, parentID+".") {
428					parentChildSet[id] = true
429				}
430			}
431		}
432	
433		var results []*types.BlockedIssue
434		for id, blockerIDs := range blockerMap {
435			if parentChildSet != nil && !parentChildSet[id] {
436				continue
437			}
438	
439			issue, ok := issueMap[id]
440			if !ok || issue == nil {
441				continue
442			}
443	
444			results = append(results, &types.BlockedIssue{
445				Issue:          *issue,
446				BlockedByCount: len(blockerIDs),
447				BlockedBy:      blockerIDs,
448			})
449		}
450	
451		// Sort by priority ASC, then created_at DESC
452		sort.Slice(results, func(i, j int) bool {
453			if results[i].Issue.Priority != results[j].Issue.Priority {
454				return results[i].Issue.Priority < results[j].Issue.Priority
455			}
456			return results[i].Issue.CreatedAt.After(results[j].Issue.CreatedAt)
457		})
458	
459		return results, nil
460	}
461	

