1050	// buildServerDSN constructs a MySQL DSN for connecting to a Dolt server.
1051	// If database is empty, connects without selecting a database (for init operations).
1052	func buildServerDSN(cfg *Config, database string) string {
1053		// go-sql-driver/mysql DSN format: user:password@tcp(host:port)/db?params
1054		// The password must not contain unescaped special characters that collide
1055		// with DSN delimiters (@ : / ?). Use go-sql-driver's Config.FormatDSN()
1056		// which handles escaping correctly.
1057		dsnCfg := mysql.Config{
1058			User:                 cfg.ServerUser,
1059			Passwd:               cfg.ServerPassword,
1060			Net:                  "tcp",
1061			Addr:                 fmt.Sprintf("%s:%d", cfg.ServerHost, cfg.ServerPort),
1062			DBName:               database,
1063			ParseTime:            true,
1064			Timeout:              5 * time.Second,
1065			ReadTimeout:          10 * time.Second,
1066			WriteTimeout:         10 * time.Second,
1067			AllowNativePasswords: true,
1068		}
1069		if cfg.ServerTLS {
