1076	// execWithLongTimeout opens a one-shot database connection with readTimeout=5m
1077	// and executes the given query. Push/pull operations can exceed the default
1078	// readTimeout when the server performs network I/O to git remotes.
1079	//
1080	// The query is wrapped in an explicit transaction (BEGIN/COMMIT) so that
1081	// DOLT_PULL merge operations succeed even when the server runs with
1082	// autocommit=1. Without this, Dolt rejects merges under autocommit because
1083	// it cannot expose conflict-resolution tables to the caller.
1084	func (s *DoltStore) execWithLongTimeout(ctx context.Context, query string, args ...any) error {
1085		cfg, err := mysql.ParseDSN(s.connStr)
1086		if err != nil {
1087			return fmt.Errorf("failed to parse DSN for long-timeout connection: %w", err)
1088		}
1089		cfg.ReadTimeout = 5 * time.Minute
1090		db, err := sql.Open("mysql", cfg.FormatDSN())
1091		if err != nil {
1092			return fmt.Errorf("failed to open long-timeout connection: %w", err)
1093		}
1094		defer db.Close()
1095		db.SetMaxOpenConns(1)
1096		tx, err := db.BeginTx(ctx, nil)
1097		if err != nil {
1098			return fmt.Errorf("failed to begin transaction: %w", err)
1099		}
1100		if _, err := tx.ExecContext(ctx, query, args...); err != nil {
1101			_ = tx.Rollback()
1102			return err
1103		}
1104		return tx.Commit()
1105	}
