1108	func openServerConnection(ctx context.Context, cfg *Config) (*sql.DB, string, error) {
1109		connStr := buildServerDSN(cfg, cfg.Database)
1110	
1111		db, err := sql.Open("mysql", connStr)
1112		if err != nil {
1113			return nil, "", fmt.Errorf("failed to open Dolt server connection: %w", err)
1114		}
1115	
1116		// Server mode supports multi-writer, configure reasonable pool size
1117		maxOpen := 10
1118		if cfg.MaxOpenConns > 0 {
1119			maxOpen = cfg.MaxOpenConns
1120		}
1121		db.SetMaxOpenConns(maxOpen)
1122		db.SetMaxIdleConns(min(5, maxOpen))
1123		db.SetConnMaxLifetime(5 * time.Minute)
1124	
1125		// Ensure database exists (may need to create it)
1126		// First connect without database to create it
1127		initConnStr := buildServerDSN(cfg, "")
1128		initDB, err := sql.Open("mysql", initConnStr)
1129		if err != nil {
1130			_ = db.Close()
1131			return nil, "", fmt.Errorf("failed to open init connection: %w", err)
1132		}
1133		defer func() { _ = initDB.Close() }()
1134	
1135		// Validate database name to prevent SQL injection via backtick escaping
1136		if err := ValidateDatabaseName(cfg.Database); err != nil {
1137			_ = db.Close()
1138			return nil, "", fmt.Errorf("invalid database name %q: %w", cfg.Database, err)
1139		}
1140	
1141		// FIREWALL: Never create test databases on the production server.
1142		// This is the last line of defense against test pollution (Clown Shows #12-#18).
1143		// Pattern-based, not env-var-based — env vars can be misconfigured or missing.
