49	// parseVersion extracts the leading integer from a migration filename like "0001_create_issues.up.sql".
50	func parseVersion(name string) (int, error) {
51		parts := strings.SplitN(name, "_", 2)
52		if len(parts) == 0 {
53			return 0, fmt.Errorf("no version prefix")
54		}
55		return strconv.Atoi(parts[0])
56	}
57	
58	// migrateUp applies all embedded .up.sql migrations that haven't been applied yet.
59	// Returns the number of migrations applied.
60	func migrateUp(ctx context.Context, tx *sql.Tx) (int, error) {
61		// Bootstrap the tracking table.
62		if _, err := tx.ExecContext(ctx, `CREATE TABLE IF NOT EXISTS schema_migrations (
63			version INT PRIMARY KEY,
64			applied_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP
65		)`); err != nil {
66			return 0, fmt.Errorf("creating schema_migrations table: %w", err)
67		}
68	
69		// Find the current version.
70		var current int
71		err := tx.QueryRowContext(ctx, "SELECT COALESCE(MAX(version), 0) FROM schema_migrations").Scan(&current)
72		if err == sql.ErrNoRows {
73			current = 0
74		} else if err != nil {
75			return 0, fmt.Errorf("reading current migration version: %w", err)
76		}
77	
78		// Fast path: if current version matches the highest embedded migration, nothing to do.
79		if current >= latestVersion() {
80			return 0, nil
81		}
82	
83		// If schema_migrations is empty but core tables already exist (e.g. restored
84		// from a DoltStore backup that doesn't track embedded migrations), backfill
85		// all versions so we don't re-run migrations that would fail on "already exists".
86		if current == 0 {
87			var tableCount int
88			if err := tx.QueryRowContext(ctx, "SELECT COUNT(*) FROM information_schema.tables WHERE table_name = 'issues' AND table_schema = DATABASE()").Scan(&tableCount); err == nil && tableCount > 0 {
89				return backfillMigrations(ctx, tx)
90			}
91		}
92	
93		// Collect and sort migration files.
94		entries, err := fs.ReadDir(upMigrations, "schema")
95		if err != nil {
96			return 0, fmt.Errorf("reading embedded migrations: %w", err)
97		}
98	
99		type migrationFile struct {
100			version int
101			name    string
102		}
103	
104		var pending []migrationFile
105		for _, e := range entries {
106			if e.IsDir() || !strings.HasSuffix(e.Name(), ".up.sql") {
107				continue
108			}
109			v, err := parseVersion(e.Name())
110			if err != nil {
111				return 0, fmt.Errorf("parsing migration filename %q: %w", e.Name(), err)
112			}
113			if v > current {
114				pending = append(pending, migrationFile{version: v, name: e.Name()})
115			}
116		}
117	
118		sort.Slice(pending, func(i, j int) bool { return pending[i].version < pending[j].version })
119	
120		if len(pending) == 0 {
121			return 0, nil
122		}
123	
124		// Apply each pending migration. The DSN has multiStatements=true,
125		// so each file is executed as a single ExecContext call.
126		for _, mf := range pending {
127			data, err := upMigrations.ReadFile("schema/" + mf.name)
128			if err != nil {
129				return 0, fmt.Errorf("reading migration %s: %w", mf.name, err)
130			}
131	
132			sql := strings.TrimSpace(string(data))
133			if sql != "" {
134				if _, err := tx.ExecContext(ctx, sql); err != nil {
135					return 0, fmt.Errorf("migration %s failed: %w", mf.name, err)
136				}
137			}
138	
139			if _, err := tx.ExecContext(ctx, "INSERT INTO schema_migrations (version) VALUES (?)", mf.version); err != nil {
140				return 0, fmt.Errorf("recording migration %s: %w", mf.name, err)
141			}
142		}
143	
144		return len(pending), nil
145	}
