func TestAddDependency(t *testing.T) {
	skipUnlessEmbeddedDolt(t)

	t.Run("basic_blocks", func(t *testing.T) {
		te := newTestEnv(t, "db")
		ctx := t.Context()

		a := &types.Issue{ID: "db-a", Title: "A", Status: types.StatusOpen, Priority: 2, IssueType: types.TypeTask}
