		te := newTestEnv(t, "id")
		ctx := t.Context()

		a := &types.Issue{ID: "id-a", Title: "A", Status: types.StatusOpen, Priority: 2, IssueType: types.TypeTask}
		b := &types.Issue{ID: "id-b", Title: "B", Status: types.StatusOpen, Priority: 2, IssueType: types.TypeTask}
