			t.Fatalf("Commit: %v", err)
		}

		// Same dep again should succeed (idempotent).
		if err := te.store.AddDependency(ctx, dep, "tester"); err != nil {
			t.Fatalf("AddDependency (second): %v", err)
		}
	})

	t.Run("type_conflict", func(t *testing.T) {
