)

func TestAddDependencyRecreatesMissingWispDependencies(t *testing.T) {
	skipUnlessEmbeddedDolt(t)

	te := newTestEnv(t, "mw")
	ctx := t.Context()

	a := &types.Issue{ID: "mw-a", Title: "A", Status: types.StatusOpen, Priority: 2, IssueType: types.TypeTask}
	b := &types.Issue{ID: "mw-b", Title: "B", Status: types.StatusOpen, Priority: 2, IssueType: types.TypeTask}
	if err := te.store.CreateIssue(ctx, a, "tester"); err != nil {
		t.Fatalf("CreateIssue A: %v", err)
	}
	if err := te.store.CreateIssue(ctx, b, "tester"); err != nil {
		t.Fatalf("CreateIssue B: %v", err)
	}
	te.store.Close()

	// Simulate a fresh Dolt working set where dolt_ignore'd wisp tables are absent.
	db, cleanup, err := embeddeddolt.OpenSQL(ctx, te.dataDir, te.database, "main")
	if err != nil {
		t.Fatalf("OpenSQL: %v", err)
	}
	for _, table := range []string{"wisp_comments", "wisp_events", "wisp_labels", "wisp_dependencies", "wisps"} {
		if _, err := db.ExecContext(ctx, "DROP TABLE IF EXISTS `"+table+"`"); err != nil {
			cleanup()
			t.Fatalf("DROP TABLE %s: %v", table, err)
		}
	}
	if err := cleanup(); err != nil {
		t.Fatalf("cleanup: %v", err)
	}

	store, err := embeddeddolt.New(ctx, filepath.Dir(te.dataDir), te.database, "main")
	if err != nil {
		t.Fatalf("New after dropping wisp tables: %v", err)
	}
	t.Cleanup(func() { store.Close() })

	dep := &types.Dependency{IssueID: "mw-b", DependsOnID: "mw-a", Type: types.DepBlocks}
	if err := store.AddDependency(ctx, dep, "tester"); err != nil {
		t.Fatalf("AddDependency after missing wisp_dependencies: %v", err)
	}
}

